using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int TotalSeats { get; set; }
    public int RemainingSeats { get; set; }
    public virtual ICollection<Ticket> Tickets { get; set; }
}

public class Ticket
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public int SeatNumber { get; set; }
    public int PurchaserId { get; set; }
    public virtual Event Event { get; set; }
    public virtual ApplicationUser Purchaser { get; set; }
}

public class ApplicationDbContext : DbContext
{
    public DbSet<Event> Events { get; set; }
    public DbSet<Ticket> Tickets { get; set; }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        base.OnModelCreating(modelBuilder);
        modelBuilder.Entity<Ticket>()
            .HasKey(t => new { t.EventId, t.SeatNumber });
        modelBuilder.Entity<Ticket>()
            .HasOne(t => t.Event)
            .WithMany(e => e.Tickets)
            .HasForeignKey(t => t.EventId)
            .OnDelete(DeleteBehavior.Restrict);
    }
}

public async Task BuyTicketAsync(int eventId, int seatCount, ApplicationUser purchaser)
{
    using var context = new ApplicationDbContext();

    var @event = await context.Events
        .Include(e => e.Tickets)
        .FirstOrDefaultAsync(e => e.Id == eventId);

    if (@event == null || @event.RemainingSeats < seatCount)
        throw new Exception("Event not found or no available seats.");

    var tickets = await context.Tickets
        .Where(t => t.EventId == eventId && !t.PurchaserId.HasValue)
        .ToListAsync();

    if (tickets.Count < seatCount)
        throw new Exception("Not enough available seats.");

    await Transaction.RunAsync(context =>
    {
        var takenTickets = tickets.Take(seatCount);

        foreach (var ticket in takenTickets)
        {
            ticket.PurchaserId = purchaser.Id;
            @event.RemainingSeats -= 1;
        }

        context.SaveChanges();
    });
}